%ORNSTEIN-UHLENBECK PROCESS dlog(z) = -the*log(z)dt + sig2*dW
%STATIONARY DISTRIBUTION IS log(z) ~ N(0,Var), where its the sum of two
%jump processes.
%     Var = 0.07;
%     zmean = exp(Var/2); %MEAN OF LOG-NORMAL DISTRIBUTION N(0,Var)
%     Corr = 0.9;
%     the = -log(Corr);
