zmax1 = 1.8925175;

zmin2 = -2.8490016;
zmax2 = 2.8490016;

z1 = linspace(zmin1,zmax1,K1);
z2 = linspace(zmin2,zmax2,K2);

tmp=repmat(z2,K1,1);
z=exp(repmat(z1,1,K2)+tmp(:)');

