tau = 15;
tau0 = ra.*(amax*.999)^(1-tau);
T = tau0.*a.^tau;
aDrift = ra.*a - T;

if ra<=0
    aDrift = ra.*a;
end



%CONSTRUCT MATRIX Bswitch SUMMARIZING EVOLUTION OF z
% yy_z1n = -1* mu1/dz1; %contep
% chi_z1n = 0* mu1/dz1 ; %past
% zeta_z1n = 1*mu1/dz1 ; %future
% 
% yy_z1p = 1* mu1/dz1; %contep
% chi_z1p = -1* mu1/dz1 ; %past
% zeta_z1p = 0*mu1/dz1 ; %future
% 
% yy_z2n =  -1*mu2/dz2;
% chi_z2n = 0* mu2/dz2 ;
% zeta_z2n = 1*mu2/dz2 ;
