% yy_z2p = 1*mu2/dz2;
% chi_z2p = -1* mu2/dz2 ;
% zeta_z2p = 0*mu2/dz2 ;

%and how a evolves to due exogenous growth
chi_a = -min(aDrift,0)./da;
yy_a  = - max(aDrift,0)./da + min(aDrift,0)./da;
zeta_a= max(aDrift,0)./da;

%Now sort into matrices
%This will be the upperdiagonal of the B_switch_a
updiag_a=zeros(I,1);%This is necessary because of the peculiar way spdiags is defined.
for j=1:J-1
    updiag_a=[updiag_a;repmat(zeta_a(j),I,1)];
end

%This will be the center diagonal of the B_switch
centdiag_a=repmat(chi_a(1)+yy_a(1),I,1);
for j=2:J-1
    centdiag_a=[centdiag_a;repmat(yy_a(j),I,1)];
end
centdiag_a=[centdiag_a;repmat(yy_a(J)+zeta_a(J),I,1)];

%This will be the lower diagonal of the B_switch
lowdiag_a=repmat(chi_a(2),I,1);
for j=3:J
    lowdiag_a =[lowdiag_a;repmat(chi_a(j),I,1)];
end

kblock =spdiags(centdiag_a,0,I*J,I*J)+spdiags(lowdiag_a,-I,I*J,I*J)+spdiags(updiag_a,I,I*J,I*J);



